  -- Logistice
  v_ResultStr VARCHAR2(2000):='';
  v_Message VARCHAR2(2000):='';
  v_Result NUMBER:=1; -- 0=failure
  v_Record_ID VARCHAR2(32);
  v_User_ID VARCHAR2(32):='0';
  v_DocAction VARCHAR2(60);
  v_DocStatus VARCHAR2(60);
  v_client_id VARCHAR2(32);
  v_org_id VARCHAR2(32);
  v_m_locator_id VARCHAR2(32);
  v_m_warehouse_id VARCHAR2(32);
  v_flag VARCHAR2(32);
  v_counter NUMBER:=0;
  v_errorlines VARCHAR2(2000);
  v_errorlines2 VARCHAR2(2000);  

  --  Parameter
  TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_m_inoutline RECORD;
BEGIN

   v_Record_ID:=p_pinstance_id;
   v_flag = '';

   For Cur_m_inoutline in(
	select a.m_inoutline_id, a.m_product_id, b.ad_org_id, b.m_warehouse_id, c.name as product, a.line, a.m_locator_id
	from m_inoutline a
	left join m_inout b on b.m_inout_id = a.m_inout_id
	left join m_product c on c.m_product_id = a.m_product_id
	where a.m_inout_id = v_Record_ID
   )
   Loop

	select count(*) INTO v_counter
	from m_warehouse a
	left join m_locator b on b.m_warehouse_id = a.m_warehouse_id
	left join swhp_wh_product c on c.m_locator_id = b.m_locator_id
	where a.m_warehouse_id = Cur_m_inoutline.m_warehouse_id --'3D65BA87C1CA4D1BAAC888C7FEA6DC9A' -- Cur_m_inoutline.m_warehouse_id
	and c.m_product_id = Cur_m_inoutline.m_product_id --'E27E97AE566C4EA7ABD449F77CF44FA0f' --Cur_m_inoutline.m_product_id
	and c.ad_org_id = Cur_m_inoutline.ad_org_id; --'EE20900630DC401D9C503C3EF98C59B4' --Cur_m_inoutline.ad_org_id

	IF (v_counter >1) THEN
		v_errorlines= coalesce(v_errorlines,'')|| ' - ' ||coalesce(Cur_m_inoutline.line,0);

	ELSIF( v_errorlines IS NULL) THEN

		select coalesce((
		select c.m_locator_id
		from m_warehouse a
		left join m_locator b on b.m_warehouse_id = a.m_warehouse_id
		left join swhp_wh_product c on c.m_locator_id = b.m_locator_id
		where a.m_warehouse_id = Cur_m_inoutline.m_warehouse_id --'3D65BA87C1CA4D1BAAC888C7FEA6DC9A' -- Cur_m_inoutline.m_warehouse_id
		and c.m_product_id = Cur_m_inoutline.m_product_id --'E27E97AE566C4EA7ABD449F77CF44FA0f' --Cur_m_inoutline.m_product_id
		and c.ad_org_id = Cur_m_inoutline.ad_org_id --'EE20900630DC401D9C503C3EF98C59B4' --Cur_m_inoutline.ad_org_id
		),'ND')
		into v_m_locator_id
		from dual;

		If(v_m_locator_id = 'ND')Then
			v_errorlines2= coalesce(v_errorlines2,'')|| ' - ' ||coalesce(Cur_m_inoutline.line,0);	
		ELSIF(v_errorlines2 IS NULL) THEN
			update m_inoutline
			set m_locator_id = v_m_locator_id
			where m_inoutline_id = Cur_m_inoutline.m_inoutline_id;
			v_flag = 'OK';
		END IF;

	END IF;
   End Loop;

   IF (v_errorlines IS NOT NULL) THEN
	RAISE_APPLICATION_ERROR(-20000,'@Swhp_MoreThanOne_Location@'||v_errorlines);
   END IF;

   IF (v_errorlines2 IS NOT NULL) THEN
	RAISE_APPLICATION_ERROR(-20000,'@Swhp_NotExist_Location@'|| v_errorlines2);
   END IF;

   IF v_flag = 'OK' THEN
	UPDATE M_INOUT SET em_swhp_process ='Y' WHERE m_inout_id = v_Record_ID; 
   END IF;
END SSDPM_ASSIGNMENT_LOCATOR
